sql:
SELECT config_name, hardware_version
FROM vehicle_configurations
WHERE software_version_id = 1;

SELECT scenario_name, description
FROM test_scenarios
ORDER BY scenario_name ASC;

SELECT health_status
FROM vehicle_health
WHERE health_status = 'bad';

SELECT DISTINCT u.user_name
FROM users u
INNER JOIN user_access_logs ual ON u.user_id = ual.user_id;

SELECT run_number
FROM test_runs
WHERE run_id = 1;

SELECT scenario_name
FROM test_scenarios
WHERE weather_conditions = 'Rainy';

SELECT run_date, success_rate
FROM test_runs
ORDER BY run_date;

SELECT log_type
FROM test_run_logs
WHERE log_type = 'Event';

SELECT COUNT(*) AS bad_health_count
FROM vehicle_health
WHERE health_status = 'bad';

